import kotlin.math.abs

fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    if (n < 4) return 0L

    val slopeMap = HashMap<Pair<Long, Long>, MutableList<Pair<Int, Int>>>()

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val x1 = points[i][0]
            val y1 = points[i][1]
            val x2 = points[j][0]
            val y2 = points[j][1]

            val dx = x2 - x1
            val dy = y2 - y1

            val g = gcd(dx, dy)
            val slope = if (g == 0L) Pair(0L, 0L) else Pair(dx / g, dy / g)

            slopeMap.getOrPut(slope) { mutableListOf() }.add(Pair(i, j))
        }
    }

    var trapezoidCount = 0L

    for ((_, pairs) in slopeMap) {
        if (pairs.size < 2) continue

        val parent = IntArray(n) { it }

        fun find(u: Int): Int {
            var current = u
            while (parent[current] != current) {
                parent[current] = parent[parent[current]]
                current = parent[current]
            }
            return current
        }

        for ((i, j) in pairs) {
            val rootI = find(i)
            val rootJ = find(j)
            if (rootI != rootJ) {
                parent[rootJ] = rootI
            }
        }

        val groups = HashMap<Int, MutableList<Int>>()
        for (u in 0 until n) {
            groups.getOrPut(find(u)) { mutableListOf() }.add(u)
        }

        for (group in groups.values) {
            val k = group.size
            if (k >= 4) {
                trapezoidCount += k * (k - 1) * (k - 2) * (k - 3) / 24 * 3
            }
        }
    }

    return trapezoidCount / 2
}

